# Build timeline of agent completions and launches
events = []

for i, msg in messages:
    ts = msg.get('timestamp', '')
    if msg.get('type') == 'queue-operation' and msg.get('operation') == 'enqueue':
        content = msg.get('content', '')
        if 'Agent' in content and '<status>completed</status>' in content:
            summary_match = re.search(r'<summary>.*?Agent "(.*?)"', content)
            desc = summary_match.group(1) if summary_match else 'unknown'
            events.append(('complete', ts, desc, i))

    if msg.get('type') == 'assistant':
        content = msg.get('message', {}).get('content', [])
        if isinstance(content, list):
            for block in content:
                if isinstance(block, dict) and block.get('type') == 'tool_use' and block.get('name') == 'Agent':
                    inp = block.get('input', {})
                    if 'resume' not in inp:
                        desc = inp.get('description', '')
                        events.append(('launch', ts, desc, i))

# Find the gap between completion and next launch of same kernel type
def kernel_key(desc):
    if 'MXFP4 MatMul' in desc: return 'MXFP4'
    if 'MLA' in desc: return 'MLA'
    if 'MoE' in desc: return 'MoE'
    return 'other'

def parse_ts(ts):
    try:
        return datetime.fromisoformat(ts.replace('Z', '+00:00'))
    except:
        return None

# Track last completion per kernel
last_complete = {}
gaps = []

for etype, ts, desc, line in events:
    k = kernel_key(desc)
    if etype == 'complete':
        last_complete[k] = (ts, line)
    elif etype == 'launch':
        if k in last_complete:
            complete_ts, complete_line = last_complete[k]
            start = parse_ts(complete_ts)
            end = parse_ts(ts)
            if start and end:
                gap_minutes = (end - start).total_seconds() / 60.0
                if gap_minutes > 0 and gap_minutes < 120:  # reasonable gaps
                    gaps.append((k, gap_minutes, complete_line, line))

print("=== RELAUNCH GAPS (time between agent completion and next launch of same kernel) ===")
from collections import defaultdict
kernel_gaps = defaultdict(list)
for k, gap, cl, ll in gaps:
    kernel_gaps[k].append(gap)

for k, gs in sorted(kernel_gaps.items()):
    avg = sum(gs) / len(gs)
    print(f"\n{k}: {len(gs)} relaunches")
    print(f"  Avg gap: {avg:.1f} min")
    print(f"  Min: {min(gs):.1f} min, Max: {max(gs):.1f} min")
    long_gaps = [g for g in gs if g > 5]
    print(f"  Gaps > 5 min: {len(long_gaps)} ({', '.join(f'{g:.1f}m' for g in sorted(long_gaps)[:10])})")

# Count how many times the orchestrator was doing non-relaunch work
print("\n=== ORCHESTRATOR INTERRUPTIONS ===")
human_interrupts = 0
for i, msg in messages:
