            entries.append((i, entry))
        except:
            pass

# Map: find Agent tool_use_id -> kernel, then queue-operation enqueue with matching tool-use-id -> task-id
agent_launches = {}  # tool_use_id -> (line, kernel)
for i, entry in entries:
    etype = entry.get('type', '')
    msg = entry.get('message', {})
    if etype == 'assistant' and isinstance(msg, dict):
        content = msg.get('content', [])
        if isinstance(content, list):
            for block in content:
                if isinstance(block, dict) and block.get('type') == 'tool_use' and block.get('name') == 'Agent':
                    inp = block.get('input', {})
                    prompt = inp.get('prompt', inp.get('task', ''))
                    tool_id = block.get('id', '')
                    kernel = 'unknown'
                    if 'mxfp4-mm' in prompt:
                        kernel = 'mxfp4-mm'
                    elif 'mixed-mla' in prompt:
                        kernel = 'mixed-mla'
                    elif 'moe-mxfp4' in prompt:
                        kernel = 'moe-mxfp4'
                    agent_launches[tool_id] = (i, kernel)

