        status = re.search(r'<status>(.*?)</status>', content)
        if tool_use_id and task_id:
            tuid = tool_use_id.group(1)
            tid = task_id.group(1)
            st = status.group(1) if status else '?'
            if tuid in agent_launches:
                line, kernel = agent_launches[tuid]
                task_to_agent[tid] = (line, kernel, st)

# Print the mapping
for tid, (line, kernel, st) in sorted(task_to_agent.items(), key=lambda x: x[1][0]):
